using System.Net;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Fix: changed from AddSingleton to AddScoped.
// .NET 9 enables ValidateOnBuild/ValidateScopes in Development, which
// rejects a singleton that captures a scoped dependency (IUserService).
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Fix: ConfigureHttpMessageHandlerBuilder is obsolete (error) in .NET 9.
// Also, the default primary handler is now SocketsHttpHandler, so casting
// to HttpClientHandler throws InvalidCastException.  Use the new API.
// Fix: .NET 9 redacts all HTTP header values in Trace logs by default.
// Chain RedactLoggedHeaders to restore visibility for debugging.
builder.Services.AddHttpClient("api")
    .UseSocketsHttpHandler((handler, _) => handler.UseCookies = false)
    .RedactLoggedHeaders(_ => false);

// Fix: ForwardedHeaders middleware now ignores X-Forwarded-* from unknown
// proxies.  Add your reverse-proxy IP to KnownProxies (or KnownNetworks).
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1")); // ← replace with actual proxy IP
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

